arguments.argument:
if textTime!=-1
{
  if global.gamePaused=false
    textTime-=1
  
  if textTime>=1 and textTime<=25
    image_alpha-=0.04
  if textTime=0
    instance_destroy()
}

if textType=1 //Marquee
{
  textWidth=string_width(screenText)
  x-=2
  if followType=0
  {
    if x<=-(string_width(screenText)*2)-4
      instance_destroy()
  }
  else if followType=1
  {
    if x<=-(string_width(screenText)*2)-4
      instance_destroy()
  }
}
